request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?originalId ?normalizedId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  FILTER(CONTAINS(STR(?model), "4e8df28e6d9f4afe970d06522542e830") || 
         CONTAINS(?originalId, "4e8df28e6d9f4afe970d06522542e830") ||
         CONTAINS(?normalizedId, "4e8df28e6d9f4afe970d06522542e830"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName ?startEvent ?startName ?endEvent ?endName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "4e8df28e6d9f4afe970d06522542e830" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  ?choreo a bboExt:Choreography .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
  OPTIONAL {
    ?startEvent a bboExt:StartEvent .
    ?startEvent tai:belongsTo ?choreo .
    OPTIONAL { ?startEvent bbo:name ?startName . }
  }
  OPTIONAL {
    ?endEvent a bboExt:EndEvent .
    ?endEvent tai:belongsTo ?choreo .
    OPTIONAL { ?endEvent bbo:name ?endName . }
  }
}
LIMIT 25
